// n8n splits array response into items, normalize
let rows = $input.all().map(x => x.json);
if (rows.length === 1 && Array.isArray(rows[0])) rows = rows[0];
const topic = rows.find(r => r && r.slug_en) || null;
if (!topic) {
  return [{ json: { empty: true, today: new Date().toISOString().slice(0,10) } }];
}
return [{ json: { ...topic, today: new Date().toISOString().slice(0,10) } }];

// Parse OpenAI API response: {choices:[{message:{content:'<json>'}}]}
const topic = $('Normalize topic').first().json;
const raw = $input.first().json;
let parsed;
try {
  const content = raw.choices?.[0]?.message?.content;
  if (!content) return [{ json: { error: 'OpenAI no content', raw_keys: Object.keys(raw) } }];
  parsed = JSON.parse(content);
} catch(e) {
  return [{ json: { error: 'JSON parse fail: ' + e.message, raw: JSON.stringify(raw).slice(0,400) } }];
}
// GPT may return in several shapes:
//   1. {segments: [...], title, ...} — correct
//   2. {scenario: [...]} — array under scenario key
//   3. {scenario: {segments: [...], title, ...}} — double-nested
//   4. [...segments...] — bare array
let scenario = null;
if (Array.isArray(parsed)) {
  scenario = { segments: parsed };
} else if (Array.isArray(parsed.scenario)) {
  scenario = { ...parsed, segments: parsed.scenario };
  delete scenario.scenario;
} else if (parsed.scenario && parsed.scenario.segments) {
  scenario = parsed.scenario;
} else if (parsed.segments) {
  scenario = parsed;
}
if (!scenario || !Array.isArray(scenario.segments) || scenario.segments.length === 0) {
  return [{ json: { error: 'no segments in scenario', raw: JSON.stringify(parsed).slice(0,400) } }];
}
// Validate segment colors — GPT may return hex instead of color names
const validColors = ['yellow','red','blue','green','pink','white'];
for (const seg of scenario.segments) {
  const vp = seg.visual_params || (seg.visual_params = {});
  if (vp.punch_color && !validColors.includes(vp.punch_color)) vp.punch_color = 'yellow';
  if (vp.cue_color && !validColors.includes(vp.cue_color)) vp.cue_color = 'blue';
  if (vp.sections) {
    for (const sec of vp.sections) {
      if (sec.cue_color && !validColors.includes(sec.cue_color)) sec.cue_color = 'blue';
    }
  }
}
// FORCE avatar_position: всегда top-right на ВСЕХ сегментах (включая hook+cta).
// До 2026-05-06 schedule был ['off','top-right','top-left','top-right','top-left','off','top-center']
// и аватар "прыгал" по позициям + пропадал на hook+seg6 — Денис 05.05 жалоба.
// Теперь стабильная единая позиция — POS_XY в composer_v2 тоже все смаплены на (730, 200).
for (let i = 0; i < scenario.segments.length; i++) {
  const seg = scenario.segments[i];
  const vp = seg.visual_params;
  vp.avatar_position = 'top-right';
}
const today = topic.today;
scenario.publish_date = today;
scenario.format = scenario.format || 'short';
scenario.lang = scenario.lang || 'ru';
const slug = scenario.slug || `R${Date.now().toString().slice(-4)}_${(topic.slug_en||'topic').replace(/[^a-zA-Z0-9_]/g,'_')}`;
scenario.slug = slug;
return [{ json: { topic_id: topic.id, slug, scenario, today } }];

