// Build YT upload payload from render result + scenario
const render = $input.first().json;
const scn = $('Build scenario payload').first().json;
const topic = $('Normalize topic').first().json;
const title = (render.scenario_title || scn.scenario.title || topic.title_ru || scn.slug).slice(0, 95) + ' #shorts';
const authorName = $env.AUTHOR_NAME || 'Author';
const authorUrl = $env.AUTHOR_URL || 'https://example.com';
const description = `${topic.title_ru}\n\n${authorName} · ${authorUrl}\n\n#AI #shorts #${(topic.slug_en || '').replace(/-/g,'')}`;
return [{ json: {
  slug: scn.slug,
  topic_id: topic.id,
  mp4_path: render.mp4_path,
  title: title.slice(0, 100),
  description,
  tags: ['AI','shorts',(topic.slug_en || '').slice(0,30)].filter(Boolean),
  lang: 'ru',
  privacy: 'public'
}}];

